import { writeOutput } from "./codegen";

const DOCS_URL = "https://www.typeform.com/developers/";
const PLACEHOLDER_VALUE = "tfp_c0ffee5afe10ca1c0ffee5afe10ca1c0ffee5afe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Typeform API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:typeform",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const typeformFirewall = {",
    '  name: "typeform",',
    '  description: "Typeform API",',
    "  placeholders: {",
    `    TYPEFORM_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.typeform.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.TYPEFORM_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Typeform firewall config...");
  const ts = generateTypeScript();
  writeOutput("typeform", ts, import.meta.dirname);
}
